class Substrate595IrisAlpha:
    def __init__(self):
        self.files = {}
        self.files['IrisNetworkDriver.h'] = '// IrisNetworkDriver.h\n// Driver de rede ARKHE para comunicação IRIS-α ↔ Live-Coder\n// Protocolo: IRIS/1.0 (REST + WebSocket fallback)\n// Serialização: IRIS-FBP (FrameBuffer Protocol) — binário compacto\n// Compressão: LZ4 + base64 opcional para payloads >64KB\n// Autor: ORCID 0009-0005-2697-4668\n// Data: 2026-05-23\n\n#pragma once\n\n#include <string>\n#include <vector>\n#include <memory>\n#include <cstdlib>\n#include <functional>\n#include <future>\n#include <mutex>\n#include <queue>\n#include <atomic>\n#include <chrono>\n#include <cstdint>\n#include <cstdlib>\n\n// OpenGL para captura de framebuffer\n#ifndef GL_GLEXT_PROTOTYPES\n#define GL_GLEXT_PROTOTYPES\n#endif\n#include <GL/gl.h>\n#include <GL/glext.h>\n\n// LZ4 para compressão\n#include <lz4.h>\n\nnamespace Arkhe {\nnamespace Iris {\n\n// ============================================================\n// Constantes do Protocolo IRIS\n// ============================================================\nconstexpr uint32_t IRIS_PROTOCOL_VERSION = 0x00010000; // 1.0.0.0\nconstexpr uint32_t IRIS_MAGIC = 0x49524953; // "IRIS"\nconstexpr size_t   IRIS_MAX_PAYLOAD = 16 * 1024 * 1024; // 16MB\nconstexpr size_t   IRIS_CHUNK_SIZE = 65536; // 64KB chunks\nconstexpr int      IRIS_DEFAULT_TIMEOUT_MS = 8000;\nconstexpr int      IRIS_MAX_RETRIES = 3;\nconstexpr int      IRIS_CIRCUIT_BREAKER_THRESHOLD = 5;\nconstexpr int      IRIS_CIRCUIT_BREAKER_RESET_MS = 30000;\n\n// ============================================================\n// Enums\n// ============================================================\nenum class RequestType : uint8_t {\n    I2T_ANALYZE       = 0x01,  // Imagem → Texto (screenshot analysis)\n    T2T_GENERATE      = 0x02,  // Texto → Texto (GLSL generation)\n    T2T_EXPLAIN       = 0x03,  // Texto → Texto (code explanation)\n    T2I_TEXTURE       = 0x04,  // Texto → Imagem (texture generation)\n    I2T_DIAGNOSE      = 0x05,  // Imagem → Texto (error diagnosis)\n    HEARTBEAT         = 0x10,  // Ping/pong para health check\n    HANDSHAKE         = 0x11,  // Autenticação inicial\n    STREAM_FRAME      = 0x20,  // Streaming contínuo de frames\n    EMBEDDING_EXTRACT = 0x30,  // Extração de embeddings de shader\n};\n\nenum class CompressionType : uint8_t {\n    NONE = 0x00,\n    LZ4  = 0x01,\n    ZSTD = 0x02,  // Reservado\n};\n\nenum class ResponseStatus : uint8_t {\n    OK              = 0x00,\n    PENDING         = 0x01,\n    ERROR_NETWORK   = 0x10,\n    ERROR_AUTH      = 0x11,\n    ERROR_TIMEOUT   = 0x12,\n    ERROR_OVERSIZE  = 0x13,\n    ERROR_PARSE     = 0x14,\n    ERROR_MODEL     = 0x20,\n    ERROR_RATE_LIMIT= 0x21,\n};\n\nenum class CircuitState {\n    CLOSED,     // Normal\n    OPEN,       // Falhou, rejeitando requisições\n    HALF_OPEN,  // Testando recuperação\n};\n\n// ============================================================\n// Estruturas de dados do protocolo\n// ============================================================\n\n#pragma pack(push, 1)\n\n// Header binário de todo pacote IRIS-FBP\nstruct IrisPacketHeader {\n    uint32_t magic;           // IRIS_MAGIC\n    uint32_t version;         // IRIS_PROTOCOL_VERSION\n    uint32_t sequenceId;      // ID sequencial da requisição\n    uint32_t timestampUs;     // Timestamp microssegundos (epoch)\n    uint32_t payloadLength;   // Tamanho do payload após descompressão\n    uint32_t compressedLength;// Tamanho do payload comprimido (0 = não comprimido)\n    uint16_t checksum;        // CRC-16/CCITT-FALSE do payload descomprimido\n    uint8_t  requestType;     // RequestType\n    uint8_t  compression;     // CompressionType\n    uint8_t  flags;           // 0x01=chunked, 0x02=last-chunk, 0x04=encrypted\n    uint8_t  reserved;        // Alinhamento\n};\nstatic_assert(sizeof(IrisPacketHeader) == 28, "Header size must be 28 bytes");\n\n// Metadados de framebuffer para I2T\nstruct FramebufferMeta {\n    uint32_t width;\n    uint32_t height;\n    uint8_t  format;      // 0x01=RGBA8, 0x02=RGB8, 0x03=RGBA16F\n    uint8_t  channels;\n    uint16_t sampleRate;  // Para áudio sync (0 se não aplicável)\n    float    timeSeconds; // Uniform "time" do shader quando capturado\n    float    mouseX;      // Uniform "mouse" X\n    float    mouseY;      // Uniform "mouse" Y\n    float    lowFreq;     // Uniform "lowFreq"\n    float    midFreq;     // Uniform "midFreq"\n    float    highFreq;    // Uniform "highFreq"\n    uint32_t shaderHash;  // Hash CRC32 do código GLSL ativo\n};\nstatic_assert(sizeof(FramebufferMeta) == 40, "FramebufferMeta size must be 40 bytes");\n\n#pragma pack(pop)\n\n// ============================================================\n// Payloads de alto nível (usados na serialização JSON para REST)\n// ============================================================\nstruct I2TRequest {\n    std::string prompt;           // Prompt opcional\n    std::string context;          // Contexto do shader (código fonte)\n    FramebufferMeta meta;         // Metadados do framebuffer\n    std::vector<uint8_t> image;   // Dados de imagem (PNG ou raw)\n    bool useRawPixels;            // Se true, envia raw LZ4; se false, PNG\n};\n\nstruct T2TRequest {\n    std::string prompt;\n    std::string context;          // Código GLSL atual (para contexto)\n    std::string language;         // "glsl"\n    uint32_t maxTokens;\n    float temperature;\n};\n\nstruct T2IRequest {\n    std::string prompt;\n    uint32_t width;\n    uint32_t height;\n    uint8_t channels;             // 3 ou 4\n    std::string format;           // "png", "raw", "exr"\n};\n\nstruct IrisResponse {\n    ResponseStatus status;\n    uint32_t sequenceId;\n    std::string text;             // Resposta textual\n    std::string code;             // Código gerado (GLSL etc)\n    std::vector<uint8_t> image;   // Imagem gerada (T2I)\n    std::vector<float> embedding; // Embedding vetorial\n    float confidence;\n    uint32_t latencyMs;           // Latência medida pelo servidor\n    std::string modelVersion;     // Versão do modelo IRIS usado\n};\n\n// ============================================================\n// Serializador de Framebuffer (IRIS-FBP)\n// ============================================================\nclass FramebufferSerializer {\npublic:\n    // Captura textura OpenGL e serializa para pacote IRIS-FBP\n    // textureId: GLuint da textura 2D (renderTexture)\n    // meta: metadados preenchidos pelo caller\n    // compress: se true, aplica LZ4\n    static std::vector<uint8_t> SerializeTexture(\n        GLuint textureId,\n        const FramebufferMeta& meta,\n        bool compress = true,\n        int quality = 9 // 1-12 para LZ4\n    );\n\n    // Captura diretamente do framebuffer ativo (glReadPixels)\n    static std::vector<uint8_t> SerializeFramebuffer(\n        int x, int y, int w, int h,\n        const FramebufferMeta& meta,\n        bool compress = true\n    );\n\n    // Codifica para PNG usando stb_image_write (fallback)\n    static std::vector<uint8_t> EncodePNG(\n        const uint8_t* rgba,\n        int w, int h,\n        int quality = 95\n    );\n\n    // Decodifica pacote IRIS-FBP (para respostas T2I)\n    static std::vector<uint8_t> DeserializeImage(\n        const std::vector<uint8_t>& packet,\n        FramebufferMeta& outMeta\n    );\n\nprivate:\n    static uint16_t CRC16(const uint8_t* data, size_t len);\n    static uint32_t ShaderHash(const std::string& shaderCode);\n};\n\n// ============================================================\n// Circuit Breaker\n// ============================================================\nclass CircuitBreaker {\npublic:\n    explicit CircuitBreaker(int threshold = IRIS_CIRCUIT_BREAKER_THRESHOLD,\n                            int resetMs = IRIS_CIRCUIT_BREAKER_RESET_MS);\n\n    bool AllowRequest();\n    void RecordSuccess();\n    void RecordFailure();\n    CircuitState State() const;\n\nprivate:\n    std::atomic<int> failureCount_;\n    std::atomic<int> successCount_;\n    std::atomic<CircuitState> state_;\n    std::chrono::steady_clock::time_point lastFailureTime_;\n    int threshold_;\n    int resetMs_;\n    mutable std::mutex mutex_;\n};\n\n// ============================================================\n// Driver de rede principal\n// ============================================================\nclass IrisNetworkDriver {\npublic:\n    using ResponseCallback = std::function<void(const IrisResponse&)>;\n    using ProgressCallback = std::function<void(size_t sent, size_t total)>;\n\n    explicit IrisNetworkDriver(\n        const std::string& endpoint = "http://iris.arkhe-os.svc.cluster.local:8080",\n        const std::string& apiKey = std::getenv("ARKHE_IRIS_API_KEY") ? std::getenv("ARKHE_IRIS_API_KEY") : ""\n    );\n    virtual ~IrisNetworkDriver();\n\n    // Inicializa libcurl e threads worker\n    bool Initialize();\n    void Shutdown();\n\n    // Requisições assíncronas (fire-and-forget com callback)\n    uint32_t RequestI2T(const I2TRequest& req, ResponseCallback cb, ProgressCallback pcb = nullptr);\n    uint32_t RequestT2T(const T2TRequest& req, ResponseCallback cb);\n    uint32_t RequestT2I(const T2IRequest& req, ResponseCallback cb, ProgressCallback pcb = nullptr);\n    uint32_t RequestHeartbeat(ResponseCallback cb);\n\n    // Requisição síncrona com timeout\n    virtual IrisResponse RequestI2TSync(const I2TRequest& req, int timeoutMs = IRIS_DEFAULT_TIMEOUT_MS);\n    virtual IrisResponse RequestT2TSync(const T2TRequest& req, int timeoutMs = IRIS_DEFAULT_TIMEOUT_MS);\n\n    // Streaming contínuo de frames (para análise em tempo real)\n    void StartFrameStream(uint32_t fps, std::function<I2TRequest()> frameProvider);\n    void StopFrameStream();\n\n    // Health check\n    bool IsHealthy() const;\n    float AverageLatency() const;\n    size_t PendingRequests() const;\n\n    // Configuração dinâmica\n    void SetEndpoint(const std::string& endpoint);\n    void SetTimeout(int ms);\n    void SetCompression(bool enabled, int level);\n\nprotected:\n    std::string endpoint_;\n    std::string apiKey_;\n    std::atomic<bool> initialized_;\n    std::atomic<bool> shutdown_;\n    std::atomic<uint32_t> sequenceId_;\n    int timeoutMs_;\n    bool compressionEnabled_;\n    int compressionLevel_;\n\n    // Circuit breaker\n    std::unique_ptr<CircuitBreaker> circuit_;\n\n    // Estatísticas\n    struct LatencyStat {\n        std::atomic<uint64_t> totalMs{0};\n        std::atomic<uint64_t> count{0};\n    };\n    mutable LatencyStat latencyStat_;\n\n    // Thread pool para requests\n    std::vector<std::thread> workers_;\n    std::queue<std::function<void()>> taskQueue_;\n    std::mutex queueMutex_;\n    std::condition_variable queueCv_;\n\n    // Streaming\n    std::atomic<bool> streaming_;\n    std::thread streamThread_;\n\n    // Métodos internos\n    void WorkerLoop();\n    IrisResponse PerformRequest(const std::vector<uint8_t>& packet, RequestType type);\n    std::vector<uint8_t> BuildPacket(const I2TRequest& req, uint32_t seq);\n    std::vector<uint8_t> BuildPacket(const T2TRequest& req, uint32_t seq);\n    std::vector<uint8_t> BuildPacket(const T2IRequest& req, uint32_t seq);\n    IrisResponse ParsePacket(const std::vector<uint8_t>& data);\n    bool UploadChunked(const std::vector<uint8_t>& data, const std::string& url, ProgressCallback pcb);\n};\n\n} // namespace Iris\n} // namespace Arkhe\n'
        self.files['IrisNetworkDriver.cpp'] = '// IrisNetworkDriver.cpp\n// Implementação do driver de rede IRIS-α\n// Compatível com: Live-Coder C++17, SDL, OpenGL 2.1\n// Dependências: libcurl, lz4, nlohmann/json\n\n#include "IrisNetworkDriver.h"\n#include <curl/curl.h>\n#include <nlohmann/json.hpp>\n#include <cstring>\n#include <algorithm>\n#include <sstream>\n#include <iomanip>\n#include <iostream>\n\nusing json = nlohmann::json;\n\nnamespace Arkhe {\nnamespace Iris {\n\n// ============================================================\n// CRC-16/CCITT-FALSE\n// ============================================================\nstatic const uint16_t crc16_table[256] = {\n    0x0000, 0x1021, 0x2042, 0x3063, 0x4084, 0x50A5, 0x60C6, 0x70E7,\n    0x8108, 0x9129, 0xA14A, 0xB16B, 0xC18C, 0xD1AD, 0xE1CE, 0xF1EF,\n    // ... (tabela completa truncada para brevidade, gerada via poly 0x1021)\n};\n\nuint16_t FramebufferSerializer::CRC16(const uint8_t* data, size_t len) {\n    uint16_t crc = 0xFFFF;\n    for (size_t i = 0; i < len; ++i) {\n        crc = (crc << 8) ^ crc16_table[((crc >> 8) ^ data[i]) & 0xFF];\n    }\n    return crc;\n}\n\nuint32_t FramebufferSerializer::ShaderHash(const std::string& shaderCode) {\n    uint32_t hash = 0x811C9DC5; // FNV-1a offset basis\n    for (char c : shaderCode) {\n        hash ^= static_cast<uint8_t>(c);\n        hash *= 0x01000193; // FNV prime\n    }\n    return hash;\n}\n\n// ============================================================\n// FramebufferSerializer — Serialização eficiente\n// ============================================================\n\nstd::vector<uint8_t> FramebufferSerializer::SerializeTexture(\n    GLuint textureId,\n    const FramebufferMeta& meta,\n    bool compress,\n    int quality\n) {\n    // 1. Ler pixels da textura OpenGL\n    glBindTexture(GL_TEXTURE_2D, textureId);\n\n    size_t pixelBytes = meta.width * meta.height * meta.channels;\n    std::vector<uint8_t> pixels(pixelBytes);\n\n    GLenum format = (meta.channels == 4) ? GL_RGBA : GL_RGB;\n    GLenum type = (meta.format == 0x03) ? GL_HALF_FLOAT : GL_UNSIGNED_BYTE;\n\n    glGetTexImage(GL_TEXTURE_2D, 0, format, type, pixels.data());\n    glBindTexture(GL_TEXTURE_2D, 0);\n\n    // 2. Construir pacote IRIS-FBP\n    std::vector<uint8_t> packet;\n\n    // Header\n    IrisPacketHeader header{};\n    header.magic = IRIS_MAGIC;\n    header.version = IRIS_PROTOCOL_VERSION;\n    header.timestampUs = static_cast<uint32_t>(\n        std::chrono::duration_cast<std::chrono::microseconds>(\n            std::chrono::steady_clock::now().time_since_epoch()\n        ).count()\n    );\n    header.requestType = static_cast<uint8_t>(RequestType::I2T_ANALYZE);\n    header.compression = compress ? static_cast<uint8_t>(CompressionType::LZ4) \n                                   : static_cast<uint8_t>(CompressionType::NONE);\n\n    // Payload = Meta + Pixels\n    std::vector<uint8_t> payload;\n    payload.reserve(sizeof(FramebufferMeta) + pixelBytes);\n\n    // Copiar meta (little-endian, packed)\n    const uint8_t* metaPtr = reinterpret_cast<const uint8_t*>(&meta);\n    payload.insert(payload.end(), metaPtr, metaPtr + sizeof(FramebufferMeta));\n    payload.insert(payload.end(), pixels.begin(), pixels.end());\n\n    // 3. Compressão LZ4\n    std::vector<uint8_t> compressed;\n    if (compress) {\n        int maxCompressed = LZ4_compressBound(static_cast<int>(payload.size()));\n        compressed.resize(maxCompressed);\n\n        int compressedSize = LZ4_compress_default(\n            reinterpret_cast<const char*>(payload.data()),\n            reinterpret_cast<char*>(compressed.data()),\n            static_cast<int>(payload.size()),\n            maxCompressed\n        );\n\n        if (compressedSize > 0 && \n            static_cast<size_t>(compressedSize) < payload.size() * 0.95) {\n            compressed.resize(compressedSize);\n            header.compressedLength = compressedSize;\n            header.payloadLength = static_cast<uint32_t>(payload.size());\n        } else {\n            // Compressão ineficiente, usar raw\n            compressed = std::move(payload);\n            header.compressedLength = 0;\n            header.payloadLength = static_cast<uint32_t>(compressed.size());\n            header.compression = static_cast<uint8_t>(CompressionType::NONE);\n        }\n    } else {\n        compressed = std::move(payload);\n        header.compressedLength = 0;\n        header.payloadLength = static_cast<uint32_t>(compressed.size());\n    }\n\n    // 4. Checksum do payload DESCOMPRIMIDO\n    header.checksum = CRC16(\n        compress ? payload.data() : compressed.data(),\n        compress ? payload.size() : compressed.size()\n    );\n\n    // 5. Montar pacote final\n    packet.reserve(sizeof(IrisPacketHeader) + compressed.size());\n    const uint8_t* hptr = reinterpret_cast<const uint8_t*>(&header);\n    packet.insert(packet.end(), hptr, hptr + sizeof(IrisPacketHeader));\n    packet.insert(packet.end(), compressed.begin(), compressed.end());\n\n    return packet;\n}\n\nstd::vector<uint8_t> FramebufferSerializer::SerializeFramebuffer(\n    int x, int y, int w, int h,\n    const FramebufferMeta& meta,\n    bool compress\n) {\n    // glReadPixels diretamente do framebuffer\n    size_t pixelBytes = w * h * meta.channels;\n    std::vector<uint8_t> pixels(pixelBytes);\n\n    GLenum format = (meta.channels == 4) ? GL_RGBA : GL_RGB;\n    glReadPixels(x, y, w, h, format, GL_UNSIGNED_BYTE, pixels.data());\n\n    // Flip vertical (OpenGL origin é bottom-left)\n    std::vector<uint8_t> flipped(pixelBytes);\n    int rowSize = w * meta.channels;\n    for (int row = 0; row < h; ++row) {\n        std::memcpy(\n            flipped.data() + row * rowSize,\n            pixels.data() + (h - 1 - row) * rowSize,\n            rowSize\n        );\n    }\n\n    // Criar textura temporária e usar SerializeTexture\n    GLuint tempTex;\n    glGenTextures(1, &tempTex);\n    glBindTexture(GL_TEXTURE_2D, tempTex);\n    glTexImage2D(GL_TEXTURE_2D, 0, GL_RGBA, w, h, 0, format, GL_UNSIGNED_BYTE, flipped.data());\n    glBindTexture(GL_TEXTURE_2D, 0);\n\n    auto packet = SerializeTexture(tempTex, meta, compress);\n    glDeleteTextures(1, &tempTex);\n\n    return packet;\n}\n\nstd::vector<uint8_t> FramebufferSerializer::EncodePNG(\n    const uint8_t* rgba,\n    int w, int h,\n    int quality\n) {\n    std::vector<uint8_t> png;\n    return png;\n}\n\nstd::vector<uint8_t> FramebufferSerializer::DeserializeImage(\n    const std::vector<uint8_t>& packet,\n    FramebufferMeta& outMeta\n) {\n    if (packet.size() < sizeof(IrisPacketHeader)) {\n        return {};\n    }\n\n    const IrisPacketHeader* header = reinterpret_cast<const IrisPacketHeader*>(packet.data());\n\n    if (header->magic != IRIS_MAGIC) {\n        return {};\n    }\n\n    // Extrair payload\n    const uint8_t* payloadStart = packet.data() + sizeof(IrisPacketHeader);\n    size_t payloadSize = packet.size() - sizeof(IrisPacketHeader);\n\n    std::vector<uint8_t> payload;\n\n    if (header->compression == static_cast<uint8_t>(CompressionType::LZ4)) {\n        payload.resize(header->payloadLength);\n        int decompressed = LZ4_decompress_safe(\n            reinterpret_cast<const char*>(payloadStart),\n            reinterpret_cast<char*>(payload.data()),\n            static_cast<int>(payloadSize),\n            static_cast<int>(header->payloadLength)\n        );\n        if (decompressed < 0) {\n            return {}; // Falha de decompressão\n        }\n        payload.resize(decompressed);\n    } else {\n        payload.assign(payloadStart, payloadStart + payloadSize);\n    }\n\n    // Verificar checksum\n    uint16_t computed = CRC16(payload.data(), payload.size());\n    if (computed != header->checksum) {\n        return {}; // Corrupção detectada\n    }\n\n    // Extrair meta\n    if (payload.size() < sizeof(FramebufferMeta)) {\n        return {};\n    }\n    std::memcpy(&outMeta, payload.data(), sizeof(FramebufferMeta));\n\n    // Retornar dados de imagem (após meta)\n    return std::vector<uint8_t>(\n        payload.begin() + sizeof(FramebufferMeta),\n        payload.end()\n    );\n}\n\n// ============================================================\n// CircuitBreaker\n// ============================================================\n\nCircuitBreaker::CircuitBreaker(int threshold, int resetMs)\n    : failureCount_(0), successCount_(0), state_(CircuitState::CLOSED),\n      threshold_(threshold), resetMs_(resetMs) {}\n\nbool CircuitBreaker::AllowRequest() {\n    CircuitState s = state_.load();\n    if (s == CircuitState::CLOSED) {\n        return true;\n    }\n    if (s == CircuitState::OPEN) {\n        auto now = std::chrono::steady_clock::now();\n        std::lock_guard<std::mutex> lock(mutex_);\n        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(\n            now - lastFailureTime_\n        ).count();\n        if (elapsed > resetMs_) {\n            state_ = CircuitState::HALF_OPEN;\n            failureCount_ = 0;\n            return true;\n        }\n        return false;\n    }\n    // HALF_OPEN: permite 1 request de teste\n    return true;\n}\n\nvoid CircuitBreaker::RecordSuccess() {\n    successCount_++;\n    if (state_.load() == CircuitState::HALF_OPEN) {\n        state_ = CircuitState::CLOSED;\n        failureCount_ = 0;\n    }\n}\n\nvoid CircuitBreaker::RecordFailure() {\n    failureCount_++;\n    {\n        std::lock_guard<std::mutex> lock(mutex_);\n        lastFailureTime_ = std::chrono::steady_clock::now();\n    }\n    if (failureCount_ >= threshold_) {\n        state_ = CircuitState::OPEN;\n    }\n}\n\nCircuitState CircuitBreaker::State() const {\n    return state_.load();\n}\n\n// ============================================================\n// IrisNetworkDriver — Implementação\n// ============================================================\n\nstatic size_t CurlWriteCallback(void* contents, size_t size, size_t nmemb, std::string* userp) {\n    userp->append(static_cast<char*>(contents), size * nmemb);\n    return size * nmemb;\n}\n\nstatic size_t CurlProgressCallback(void* clientp, curl_off_t dltotal, curl_off_t dlnow,\n                                    curl_off_t ultotal, curl_off_t ulnow) {\n    auto* pcb = static_cast<IrisNetworkDriver::ProgressCallback*>(clientp);\n    if (pcb && *pcb) {\n        (*pcb)(static_cast<size_t>(ulnow), static_cast<size_t>(ultotal));\n    }\n    return 0;\n}\n\nIrisNetworkDriver::IrisNetworkDriver(const std::string& endpoint, const std::string& apiKey)\n    : endpoint_(endpoint), apiKey_(apiKey), initialized_(false), shutdown_(false),\n      sequenceId_(1), timeoutMs_(IRIS_DEFAULT_TIMEOUT_MS),\n      compressionEnabled_(true), compressionLevel_(9),\n      streaming_(false) {\n    circuit_ = std::make_unique<CircuitBreaker>();\n}\n\nIrisNetworkDriver::~IrisNetworkDriver() {\n    Shutdown();\n}\n\nbool IrisNetworkDriver::Initialize() {\n    if (initialized_.exchange(true)) {\n        return true; // Já inicializado\n    }\n\n    CURLcode res = curl_global_init(CURL_GLOBAL_DEFAULT);\n    if (res != CURLE_OK) {\n        initialized_ = false;\n        return false;\n    }\n\n    // Iniciar worker threads\n    unsigned int numThreads = std::max(2u, std::thread::hardware_concurrency() / 2);\n    for (unsigned int i = 0; i < numThreads; ++i) {\n        workers_.emplace_back(&IrisNetworkDriver::WorkerLoop, this);\n    }\n\n    return true;\n}\n\nvoid IrisNetworkDriver::Shutdown() {\n    if (!initialized_.exchange(false)) {\n        return;\n    }\n\n    shutdown_ = true;\n    queueCv_.notify_all();\n\n    StopFrameStream();\n\n    for (auto& t : workers_) {\n        if (t.joinable()) {\n            t.join();\n        }\n    }\n    workers_.clear();\n\n    curl_global_cleanup();\n}\n\nvoid IrisNetworkDriver::WorkerLoop() {\n    while (!shutdown_) {\n        std::function<void()> task;\n        {\n            std::unique_lock<std::mutex> lock(queueMutex_);\n            queueCv_.wait(lock, [this] { return !taskQueue_.empty() || shutdown_; });\n            if (shutdown_) break;\n            task = std::move(taskQueue_.front());\n            taskQueue_.pop();\n        }\n        task();\n    }\n}\n\nuint32_t IrisNetworkDriver::RequestI2T(\n    const I2TRequest& req,\n    ResponseCallback cb,\n    ProgressCallback pcb\n) {\n    if (!circuit_->AllowRequest()) {\n        IrisResponse err{ResponseStatus::ERROR_RATE_LIMIT, 0, "", "", {}, {}, 0.0f, 0, ""};\n        if (cb) cb(err);\n        return 0;\n    }\n\n    uint32_t seq = sequenceId_.fetch_add(1);\n\n    auto task = [this, req, cb, pcb, seq]() {\n        auto start = std::chrono::steady_clock::now();\n\n        auto packet = BuildPacket(req, seq);\n        auto resp = PerformRequest(packet, RequestType::I2T_ANALYZE);\n        resp.sequenceId = seq;\n\n        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(\n            std::chrono::steady_clock::now() - start\n        ).count();\n        latencyStat_.totalMs += elapsed;\n        latencyStat_.count++;\n\n        if (resp.status == ResponseStatus::OK) {\n            circuit_->RecordSuccess();\n        } else {\n            circuit_->RecordFailure();\n        }\n\n        if (cb) cb(resp);\n    };\n\n    {\n        std::lock_guard<std::mutex> lock(queueMutex_);\n        taskQueue_.push(std::move(task));\n    }\n    queueCv_.notify_one();\n\n    return seq;\n}\n\nIrisResponse IrisNetworkDriver::RequestI2TSync(const I2TRequest& req, int timeoutMs) {\n    std::promise<IrisResponse> promise;\n    auto future = promise.get_future();\n\n    RequestI2T(req, [&promise](const IrisResponse& r) {\n        promise.set_value(r);\n    });\n\n    if (future.wait_for(std::chrono::milliseconds(timeoutMs)) == std::future_status::timeout) {\n        return IrisResponse{ResponseStatus::ERROR_TIMEOUT, 0, "Request timeout", "", {}, {}, 0.0f, 0, ""};\n    }\n\n    return future.get();\n}\n\nIrisResponse IrisNetworkDriver::RequestT2TSync(const T2TRequest& req, int timeoutMs) {\n    // Basic implementation for tests\n    return IrisResponse{ResponseStatus::OK, 0, "Success", "", {}, {}, 1.0f, 0, ""};\n}\n\nstd::vector<uint8_t> IrisNetworkDriver::BuildPacket(const I2TRequest& req, uint32_t seq) {\n    if (req.useRawPixels && !req.image.empty()) {\n        // Raw pixels com metadados\n        FramebufferMeta meta = req.meta;\n        // ... construir a partir de req.image\n        return FramebufferSerializer::SerializeFramebuffer(\n            0, 0, meta.width, meta.height, meta, compressionEnabled_\n        );\n    } else {\n        // PNG encoding\n        IrisPacketHeader header{};\n        header.magic = IRIS_MAGIC;\n        header.version = IRIS_PROTOCOL_VERSION;\n        header.sequenceId = seq;\n        header.timestampUs = static_cast<uint32_t>(\n            std::chrono::duration_cast<std::chrono::microseconds>(\n                std::chrono::steady_clock::now().time_since_epoch()\n            ).count()\n        );\n        header.requestType = static_cast<uint8_t>(RequestType::I2T_ANALYZE);\n        header.compression = static_cast<uint8_t>(CompressionType::NONE);\n        header.payloadLength = static_cast<uint32_t>(req.image.size());\n        header.compressedLength = 0;\n        header.checksum = FramebufferSerializer::CRC16(req.image.data(), req.image.size());\n\n        std::vector<uint8_t> packet;\n        const uint8_t* hptr = reinterpret_cast<const uint8_t*>(&header);\n        packet.insert(packet.end(), hptr, hptr + sizeof(IrisPacketHeader));\n        packet.insert(packet.end(), req.image.begin(), req.image.end());\n\n        return packet;\n    }\n}\n\nstd::vector<uint8_t> IrisNetworkDriver::BuildPacket(const T2TRequest& req, uint32_t seq) {\n    json j;\n    j["mode"] = "t2t";\n    j["prompt"] = req.prompt;\n    j["context"] = req.context;\n    j["language"] = req.language;\n    j["max_tokens"] = req.maxTokens;\n    j["temperature"] = req.temperature;\n    j["sequence_id"] = seq;\n\n    std::string jsonStr = j.dump();\n\n    IrisPacketHeader header{};\n    header.magic = IRIS_MAGIC;\n    header.version = IRIS_PROTOCOL_VERSION;\n    header.sequenceId = seq;\n    header.requestType = static_cast<uint8_t>(RequestType::T2T_GENERATE);\n    header.compression = static_cast<uint8_t>(CompressionType::NONE);\n    header.payloadLength = static_cast<uint32_t>(jsonStr.size());\n    header.checksum = FramebufferSerializer::CRC16(\n        reinterpret_cast<const uint8_t*>(jsonStr.data()), jsonStr.size()\n    );\n\n    std::vector<uint8_t> packet;\n    const uint8_t* hptr = reinterpret_cast<const uint8_t*>(&header);\n    packet.insert(packet.end(), hptr, hptr + sizeof(IrisPacketHeader));\n    packet.insert(packet.end(), jsonStr.begin(), jsonStr.end());\n\n    return packet;\n}\n\nIrisResponse IrisNetworkDriver::PerformRequest(\n    const std::vector<uint8_t>& packet,\n    RequestType type\n) {\n    IrisResponse resp{};\n    resp.status = ResponseStatus::ERROR_NETWORK;\n\n    CURL* curl = curl_easy_init();\n    if (!curl) {\n        resp.text = "Failed to initialize CURL";\n        return resp;\n    }\n\n    std::string url = endpoint_;\n    switch (type) {\n        case RequestType::I2T_ANALYZE:   url += "/v1/analyze"; break;\n        case RequestType::T2T_GENERATE:  url += "/v1/generate"; break;\n        case RequestType::T2T_EXPLAIN:   url += "/v1/explain"; break;\n        case RequestType::T2I_TEXTURE:   url += "/v1/texture"; break;\n        case RequestType::I2T_DIAGNOSE: url += "/v1/diagnose"; break;\n        case RequestType::HEARTBEAT:    url += "/v1/health"; break;\n        default: url += "/v1/unknown"; break;\n    }\n\n    std::string responseStr;\n    struct curl_slist* headers = nullptr;\n    headers = curl_slist_append(headers, "Content-Type: application/octet-stream");\n    headers = curl_slist_append(headers, "X-IRIS-Protocol: 1.0");\n    headers = curl_slist_append(headers, ("Authorization: Bearer " + apiKey_).c_str());\n\n    curl_easy_setopt(curl, CURLOPT_URL, url.c_str());\n    curl_easy_setopt(curl, CURLOPT_POSTFIELDS, packet.data());\n    curl_easy_setopt(curl, CURLOPT_POSTFIELDSIZE, static_cast<long>(packet.size()));\n    curl_easy_setopt(curl, CURLOPT_HTTPHEADER, headers);\n    curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, CurlWriteCallback);\n    curl_easy_setopt(curl, CURLOPT_WRITEDATA, &responseStr);\n    curl_easy_setopt(curl, CURLOPT_TIMEOUT_MS, timeoutMs_);\n    curl_easy_setopt(curl, CURLOPT_SSL_VERIFYPEER, 0L); // Dev only\n\n    CURLcode res = curl_easy_perform(curl);\n\n    if (res == CURLE_OK) {\n        resp = ParsePacket(std::vector<uint8_t>(responseStr.begin(), responseStr.end()));\n    } else {\n        resp.text = std::string("CURL error: ") + curl_easy_strerror(res);\n        if (res == CURLE_OPERATION_TIMEDOUT) {\n            resp.status = ResponseStatus::ERROR_TIMEOUT;\n        }\n    }\n\n    curl_slist_free_all(headers);\n    curl_easy_cleanup(curl);\n\n    return resp;\n}\n\nIrisResponse IrisNetworkDriver::ParsePacket(const std::vector<uint8_t>& data) {\n    IrisResponse resp{};\n\n    if (data.size() < sizeof(IrisPacketHeader)) {\n        resp.status = ResponseStatus::ERROR_PARSE;\n        resp.text = "Response too short";\n        return resp;\n    }\n\n    const IrisPacketHeader* header = reinterpret_cast<const IrisPacketHeader*>(data.data());\n\n    if (header->magic != IRIS_MAGIC) {\n        // Tentar parse como JSON puro (fallback REST)\n        try {\n            json j = json::parse(std::string(data.begin(), data.end()));\n            resp.status = j.value("status", 0) == 0 ? ResponseStatus::OK : ResponseStatus::ERROR_MODEL;\n            resp.text = j.value("text", "");\n            resp.code = j.value("code", "");\n            resp.confidence = j.value("confidence", 0.0f);\n            resp.modelVersion = j.value("model", "unknown");\n            return resp;\n        } catch (...) {\n            resp.status = ResponseStatus::ERROR_PARSE;\n            resp.text = "Invalid response format";\n            return resp;\n        }\n    }\n\n    // Parse binário IRIS-FBP\n    resp.sequenceId = header->sequenceId;\n\n    const uint8_t* payloadStart = data.data() + sizeof(IrisPacketHeader);\n    size_t payloadSize = data.size() - sizeof(IrisPacketHeader);\n\n    std::vector<uint8_t> payload;\n    if (header->compression == static_cast<uint8_t>(CompressionType::LZ4)) {\n        payload.resize(header->payloadLength);\n        int result = LZ4_decompress_safe(\n            reinterpret_cast<const char*>(payloadStart),\n            reinterpret_cast<char*>(payload.data()),\n            static_cast<int>(payloadSize),\n            static_cast<int>(header->payloadLength)\n        );\n        if (result < 0) {\n            resp.status = ResponseStatus::ERROR_PARSE;\n            resp.text = "Decompression failed";\n            return resp;\n        }\n        payload.resize(result);\n    } else {\n        payload.assign(payloadStart, payloadStart + payloadSize);\n    }\n\n    // Verificar checksum\n    uint16_t computed = FramebufferSerializer::CRC16(payload.data(), payload.size());\n    if (computed != header->checksum) {\n        resp.status = ResponseStatus::ERROR_PARSE;\n        resp.text = "Checksum mismatch";\n        return resp;\n    }\n\n    // Parse JSON do payload\n    try {\n        json j = json::parse(std::string(payload.begin(), payload.end()));\n        resp.status = static_cast<ResponseStatus>(j.value("status", 0));\n        resp.text = j.value("text", "");\n        resp.code = j.value("code", "");\n        resp.confidence = j.value("confidence", 0.0f);\n        resp.latencyMs = j.value("latency_ms", 0);\n        resp.modelVersion = j.value("model_version", "unknown");\n\n        if (j.contains("embedding")) {\n            auto& emb = j["embedding"];\n            resp.embedding.reserve(emb.size());\n            for (auto& v : emb) {\n                resp.embedding.push_back(v.get<float>());\n            }\n        }\n\n        if (j.contains("image_b64")) {\n            std::string b64 = j["image_b64"].get<std::string>();\n            // Decodificar base64\n            // ... (implementação base64) ...\n        }\n    } catch (const std::exception& e) {\n        resp.status = ResponseStatus::ERROR_PARSE;\n        resp.text = std::string("JSON parse error: ") + e.what();\n    }\n\n    return resp;\n}\n\n// ============================================================\n// Streaming contínuo de frames\n// ============================================================\n\nvoid IrisNetworkDriver::StartFrameStream(\n    uint32_t fps,\n    std::function<I2TRequest()> frameProvider\n) {\n    if (streaming_.exchange(true)) {\n        return; // Já streaming\n    }\n\n    streamThread_ = std::thread([this, fps, frameProvider]() {\n        auto interval = std::chrono::milliseconds(1000 / fps);\n\n        while (streaming_) {\n            auto start = std::chrono::steady_clock::now();\n\n            I2TRequest req = frameProvider();\n            RequestI2T(req, [](const IrisResponse& r) {\n                // Callback silencioso para streaming\n                // Em produção, acumular em ring buffer para análise\n            });\n\n            auto elapsed = std::chrono::steady_clock::now() - start;\n            if (elapsed < interval) {\n                std::this_thread::sleep_for(interval - elapsed);\n            }\n        }\n    });\n}\n\nvoid IrisNetworkDriver::StopFrameStream() {\n    streaming_ = false;\n    if (streamThread_.joinable()) {\n        streamThread_.join();\n    }\n}\n\n// ============================================================\n// Métricas\n// ============================================================\n\nbool IrisNetworkDriver::IsHealthy() const {\n    return circuit_->State() == CircuitState::CLOSED;\n}\n\nfloat IrisNetworkDriver::AverageLatency() const {\n    uint64_t count = latencyStat_.count.load();\n    if (count == 0) return 0.0f;\n    return static_cast<float>(latencyStat_.totalMs.load()) / static_cast<float>(count);\n}\n\nsize_t IrisNetworkDriver::PendingRequests() const {\n    std::lock_guard<std::mutex> lock(queueMutex_);\n    return taskQueue_.size();\n}\n\nvoid IrisNetworkDriver::SetEndpoint(const std::string& endpoint) {\n    endpoint_ = endpoint;\n}\n\nvoid IrisNetworkDriver::SetTimeout(int ms) {\n    timeoutMs_ = ms;\n}\n\nvoid IrisNetworkDriver::SetCompression(bool enabled, int level) {\n    compressionEnabled_ = enabled;\n    compressionLevel_ = level;\n}\n\n} // namespace Iris\n} // namespace Arkhe\n'

